/**
 * Tiny event emitter shared by both runtime implementations.
 * Throwing listeners are isolated.
 */

import type { RuntimeEvent, RuntimeEventListener } from './types';

export class RuntimeEventBus {
  private listeners = new Set<RuntimeEventListener>();

  on(listener: RuntimeEventListener): () => void {
    this.listeners.add(listener);
    return () => this.listeners.delete(listener);
  }

  emit(event: RuntimeEvent): void {
    for (const listener of this.listeners) {
      try {
        listener(event);
      } catch (err) {
        console.error('[nova-ar-viewer] runtime listener threw', err);
      }
    }
  }

  clear(): void {
    this.listeners.clear();
  }

  size(): number {
    return this.listeners.size;
  }
}
